import{_ as e,o as l,c as r,a3 as a}from"./chunks/framework.d0TBG0Rg.js";const f=JSON.parse('{"title":"群规与全服公告","description":"官方交流群群规和公告，进群必看。","frontmatter":{"title":"群规与全服公告","description":"官方交流群群规和公告，进群必看。"},"headers":[],"relativePath":"rules.md","filePath":"rules.md"}'),d={name:"rules.md"};function s(n,t,o,i,g,c){return l(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="群规与公告" tabindex="-1">群规与公告 <a class="header-anchor" href="#群规与公告" aria-label="Permalink to &quot;群规与公告&quot;">​</a></h1><br><div class="mzk-card mzk-card--red"><h3>行为红线 (违者直接移出群聊)</h3><p>底线规定，触碰即踢：</p><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">条目</th><th style="text-align:left;">禁止事项</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>1</strong></td><td style="text-align:left;">严禁讨论政治敏感话题、发布 R18 (色情) 内容及恶俗引战。</td></tr><tr><td style="text-align:left;"><strong>2</strong></td><td style="text-align:left;">严禁情绪化发言、“暴躁老哥”行为、无脑喷人或人身攻击。</td></tr><tr><td style="text-align:left;"><strong>3</strong></td><td style="text-align:left;">严禁搬运或传播引起他人不适的低质量（“大便”）言论。</td></tr><tr><td style="text-align:left;"><strong>4</strong></td><td style="text-align:left;">本群 CP 自由，请保持互相尊重，严禁踩雷引战。</td></tr></tbody></table></div></div><div class="mzk-card mzk-card--blue"><h3>Bot 账号信息与使用规范</h3><p> 使用前必须完整阅读《用户使用协议》与《免责声明》。 </p><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">Bot 名称</th><th style="text-align:left;">QQ 号</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Mizuki Bot (Amia_晓山瑞希)</strong></td><td style="text-align:left;"><code>3889004352</code></td></tr></tbody></table></div><div class="mzk-alert"><p style="font-weight:bold;margin:0 0 10px 0;"> Bot 使用与触发限制 </p><ul><li><strong>正确触发</strong>：触发功能请直接发送对应指令文本，<strong>严禁 @机器人！</strong></li><li><strong>私聊限制</strong>：Bot 的 PJSK 功能 <strong>不支持私聊</strong>。若私聊请求过多可能触发风控导致您被系统拉黑。</li></ul></div></div><div class="mzk-card mzk-card--green"><h3>管理、求助与数据协助</h3><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">详细说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>提问的智慧</strong></td><td style="text-align:left;">遇到常规问题，请优先使用必应 (Bing) 搜索或查阅本网站文档。<strong>严禁直接 @管理员 发送无前因后果、无厘头的问题。</strong></td></tr><tr><td style="text-align:left;"><strong>拉 Bot 咨询</strong></td><td style="text-align:left;">若不清楚如何拉取 Bot，可咨询群管或添加群主 QQ。群内公告可能存在延迟，最新信息以群主动态为准。</td></tr><tr><td style="text-align:left;"><strong>纠纷与 Bug 处理</strong></td><td style="text-align:left;">遇到报错、Bug 或群内纠纷，请直接 @以下代理群主：<code>歡迎來到1918年</code>、<code>m</code>、<code>同道中人</code>、<code>还是FBF吖~</code>。以上四位拥有免群主审核直接处理事务的权限。</td></tr><tr><td style="text-align:left;"><strong>无故艾特处罚</strong></td><td style="text-align:left;">群主及管理员并非 24 小时在线。若发现无事随意艾特管理团队的行为，将进行阶梯式禁言处理。</td></tr><tr><td style="text-align:left;"><strong>国服数据协助</strong></td><td style="text-align:left;">群主可协助进行“国服烤森”数据上传以便正常使用 PJSK B30/39 功能。<br><strong>条件</strong>：必须提供手机号和验证码，且在此之前必须至少打过一局。<br><strong>声明</strong>：此项协助并非义务，仅在群主空闲时处理。</td></tr></tbody></table></div></div><div class="mzk-card mzk-card--purple"><h3>鸣谢与相关链接</h3><p style="font-weight:bold;">特别鸣谢 (排名不分先后)：</p><ul><li>感谢 <strong>m</strong> 为 Bot 设计头像。</li><li>感谢 <strong>同道中人</strong> 与 <strong>Sirius</strong> 提供软硬件技术支持。</li></ul><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">资源名称</th><th style="text-align:left;">访问地址</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>官网</strong></td><td style="text-align:left;"><a href="https://help.mizuki.top" target="_blank" style="color:var(--vp-c-brand-1);text-decoration:underline;">help.mizuki.top</a></td></tr><tr><td style="text-align:left;"><strong>提问的智慧</strong></td><td style="text-align:left;"><a href="/asking.html" style="color:var(--vp-c-brand-1);text-decoration:underline;">点击阅读《提问的智慧》指南</a></td></tr><tr><td style="text-align:left;"><strong>用户使用协议</strong></td><td style="text-align:left;"><a href="/agreement.html" style="color:var(--vp-c-brand-1);text-decoration:underline;">点击阅读《用户使用协议》</a></td></tr><tr><td style="text-align:left;"><strong>问题反馈</strong></td><td style="text-align:left;"><a href="https://wrdzgzs2024.feishu.cn/share/base/form/shrcnAK9hJGLF40ga1frnQo7XLg" target="_blank" style="color:var(--vp-c-brand-1);text-decoration:underline;">点击填写飞书反馈表单</a></td></tr><tr><td style="text-align:left;"><strong>账号封禁申诉</strong></td><td style="text-align:left;"><a href="https://wrdzgzs2024.feishu.cn/share/base/form/shrcnEQdtCjp8VMXAdhdHSKKt2b" target="_blank" style="color:var(--vp-c-brand-1);text-decoration:underline;">点击填写飞书申诉表单</a></td></tr></tbody></table></div></div>',6)])])}const y=e(d,[["render",s]]);export{f as __pageData,y as default};
